#!/usr/bin/env bash
set -euo pipefail; source "$(dirname "$0")/lib/android-test.sh"; abi=x86_64;serial=emulator-5554;timeout=30;while (($#));do case "$1" in --android-abi)abi="${2:?}";shift 2;;--serial)serial="${2:?}";shift 2;;--timeout-seconds)timeout="${2:?}";shift 2;;*)archphene_die "unknown argument: $1";;esac;done;archphene_test_init "$serial";apk="$ARCHPHENE_ROOT/prototypes/accessibility-capability-probe/out-$abi/archphene-accessibility-probe.apk";archphene_require_file "$apk";package=org.archphene.accessibilityprobe;service="$package/org.archphene.bridge.ProbeAccessibilityService";old_services="$(archphene_adb_run shell settings get secure enabled_accessibility_services|tr -d '\r')";old_enabled="$(archphene_adb_run shell settings get secure accessibility_enabled|tr -d '\r')";restore(){ [[ "$old_services" == null || -z "$old_services" ]] && archphene_adb_run shell settings delete secure enabled_accessibility_services >/dev/null 2>&1 || archphene_adb_run shell settings put secure enabled_accessibility_services "$old_services" >/dev/null 2>&1 || true;archphene_adb_run shell settings put secure accessibility_enabled "$old_enabled" >/dev/null 2>&1 || true;};trap restore EXIT;archphene_adb_run install -r "$apk" >/dev/null;archphene_adb_run shell settings put secure enabled_accessibility_services "$service";archphene_adb_run shell settings put secure accessibility_enabled 1;archphene_adb_run logcat -c;archphene_adb_run shell am start -W -n "$package/org.archphene.bridge.AccessibilityProbeActivity" >/dev/null;log="$(archphene_wait_log 'Accessibility broker listening|AccessibilityService connected' "$timeout" 'ArchpheneCapabilities AndroidRuntime *:S')";[[ "$log" != *'FATAL EXCEPTION'* ]] || archphene_die 'accessibility probe crashed';archphene_note "Android accessibility bridge passed on $serial ($abi): service binding and native broker startup verified."
